test.config:
indexer
{
	mem_limit		= 16M
}

searchd
{

}

source test_src
{
	type			= mysql

	sql_query		= select id, guid from test_docs order by id
	sql_field_string	= guid
	sql_attr_multi		= uint mva from query; select id, tag from test_tags order by id, tag
}

index test_mvaq
{
	source			= test_src
	path			= /test_mvaq
	columnar_attrs		= *
}

index test_mvaq_explicit
{
	source			= test_src
	path			= /test_mvaq_explicit
	columnar_attrs		= mva
}

queries.sphinxql:
desc test_mvaq;
select id,guid,mva,length(mva) len from test_mvaq order by id asc;
select id from test_mvaq where any(mva)=12;
select id,guid,mva,length(mva) len from test_mvaq where id=3;

desc test_mvaq_explicit;
select id,guid,mva,length(mva) len from test_mvaq_explicit order by id asc;
select id from test_mvaq_explicit where any(mva)=12;
select id,guid,mva,length(mva) len from test_mvaq_explicit where id=3;
